#include <stdio.h>
#include <string.h>

int main() {
    char p[1000];
    scanf("%s", p);
    int i = 0;
    char r[1000] = "";
    int c = 0;
    while (i < strlen(p)) {
        if (p[i] != '/') {
            strncat(r, &p[i], 1);
            c = 0;
