            strncat(r, &p[i], 1);
            c = 1;
        }
        i++;
    }
    if (r[strlen(r) - 1] == '/' && strlen(r) > 1) {
        r[strlen(r) - 1] = '\0';
    }
    printf("%s\n", r);
    return 0;
}
